/* =============================================================================
   AURA ALPHA -- Revenue Analytics Dashboard (Admin-Only)
   Conversion funnel, MRR, ARPU, LTV, churn, tier breakdown, rentals,
   compute credits, top converting pages, cohort retention.
   Auto-refreshes every 60 seconds.
   ============================================================================= */
import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';
import usePageTitle from '../hooks/usePageTitle';
import s from './RevenueDashboardPage.module.css';

const REFRESH_INTERVAL = 60_000;

// ── Formatting helpers ──────────────────────────────────────────────────────
const fmtNum = (n) => (n ?? 0).toLocaleString('en-US');
const fmtPct = (n) => `${(n ?? 0).toFixed(1)}%`;
const fmtUsd = (cents) => {
  const d = (cents ?? 0) / 100;
  if (d >= 100_000) return `$${(d / 1000).toFixed(0)}k`;
  if (d >= 1_000) return `$${(d / 1000).toFixed(1)}k`;
  return `$${d.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

function trendArrow(val) {
  if (val > 0) return { arrow: '\u25B2', cls: s.trendUp };
  if (val < 0) return { arrow: '\u25BC', cls: s.trendDown };
  return { arrow: '\u25AC', cls: s.trendFlat };
}

// ── Section Header ──────────────────────────────────────────────────────────
function SectionHeader({ icon, title }) {
  return (
    <div className={s.sectionHeader}>
      <span className={s.sectionIcon}>{icon}</span>
      <h2 className={s.sectionTitle}>{title}</h2>
      <div className={s.sectionDivider} />
    </div>
  );
}

// ── Cohort retention color ──────────────────────────────────────────────────
function cohortClass(pct) {
  if (pct == null) return s.cohortEmpty;
  if (pct >= 70) return s.cohortHigh;
  if (pct >= 50) return s.cohortMid;
  return s.cohortLow;
}

// ═════════════════════════════════════════════════════════════════════════════
export default function RevenueDashboardPage() {
  usePageTitle('Revenue Analytics');

  const [summary, setSummary] = useState(null);
  const [funnel, setFunnel] = useState(null);
  const [tiers, setTiers] = useState(null);
  const [rentals, setRentals] = useState(null);
  const [cohorts, setCohorts] = useState(null);
  const [pages, setPages] = useState(null);
  const [compute, setCompute] = useState(null);
  const [loading, setLoading] = useState(true);
  const timer = useRef(null);

  const fetchAll = useCallback(async () => {
    try {
      const [sum, fun, tier, rent, coh, pg, comp] = await Promise.all([
        api('/api/admin/revenue/summary'),
        api('/api/admin/revenue/funnel'),
        api('/api/admin/revenue/by-tier'),
        api('/api/admin/revenue/rentals'),
        api('/api/admin/revenue/cohorts'),
        api('/api/admin/revenue/converting-pages'),
        api('/api/admin/revenue/compute-credits'),
      ]);
      if (sum) setSummary(sum);
      if (fun) setFunnel(fun);
      if (tier) setTiers(tier);
      if (rent) setRentals(rent);
      if (coh) setCohorts(coh);
      if (pg) setPages(pg);
      if (comp) setCompute(comp);
    } catch (e) {
      console.warn('Revenue fetch error:', e);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAll();
    timer.current = setInterval(fetchAll, REFRESH_INTERVAL);
    return () => clearInterval(timer.current);
  }, [fetchAll]);

  if (loading) {
    return <div className={s.loading}>Loading revenue analytics...</div>;
  }

  const trend = summary ? trendArrow(summary.mrr_trend_pct) : trendArrow(0);
  const maxTierMrr = tiers?.tiers
    ? Math.max(...tiers.tiers.map((t) => t.mrr_cents), 1)
    : 1;
  const maxFunnel = funnel?.stages?.[0]?.count || 1;
  const maxChurn = summary?.churn_trend
    ? Math.max(...summary.churn_trend, 1)
    : 5;

  // Funnel stage colors (gradient from blue to green)
  const FUNNEL_COLORS = ['#60A5FA', '#58A6FF', '#36BDF0', '#22D3EE', '#22C55E', '#3FB950'];

  return (
    <div className={s.page}>
      {/* ── Header ─────────────────────────────────────────── */}
      <div className={s.header}>
        <div className={s.headerLeft}>
          <h1 className={s.title}>Revenue Analytics</h1>
          <span className={s.adminBadge}>ADMIN</span>
        </div>
        <button className={s.refreshBtn} onClick={() => { setLoading(true); fetchAll(); }}>
          Refresh
        </button>
      </div>

      {/* ── KPI Cards ──────────────────────────────────────── */}
      <SectionHeader icon="$" title="Key Metrics" />
      <div className={s.kpiGrid}>
        <div className={s.kpiCard}>
          <div className={s.kpiLabel}>Monthly Recurring Revenue</div>
          <div className={s.kpiValue} style={{ color: '#22C55E' }}>
            {fmtUsd(summary?.mrr_cents)}
          </div>
          <div className={`${s.kpiSub} ${trend.cls}`}>
            {trend.arrow} {fmtPct(Math.abs(summary?.mrr_trend_pct ?? 0))} vs last month
          </div>
        </div>

        <div className={s.kpiCard}>
          <div className={s.kpiLabel}>ARPU</div>
          <div className={s.kpiValue}>{fmtUsd(summary?.arpu_cents)}</div>
          <div className={s.kpiSub} style={{ color: '#8B949E' }}>
            Avg Revenue Per User
          </div>
        </div>

        <div className={s.kpiCard}>
          <div className={s.kpiLabel}>Lifetime Value</div>
          <div className={s.kpiValue} style={{ color: '#A78BFA' }}>
            {fmtUsd(summary?.ltv_cents)}
          </div>
          <div className={s.kpiSub} style={{ color: '#8B949E' }}>
            ARPU / Churn Rate
          </div>
        </div>

        <div className={s.kpiCard}>
          <div className={s.kpiLabel}>Churn Rate</div>
          <div className={s.kpiValue} style={{ color: '#EF4444' }}>
            {fmtPct(summary?.churn_rate_pct)}
          </div>
          <div className={s.kpiSub} style={{ color: '#8B949E' }}>
            Monthly
          </div>
        </div>

        <div className={s.kpiCard}>
          <div className={s.kpiLabel}>Paying Users</div>
          <div className={s.kpiValue}>{fmtNum(summary?.total_paying)}</div>
          <div className={s.kpiSub} style={{ color: '#8B949E' }}>
            of {fmtNum(summary?.total_users)} total
          </div>
        </div>

        <div className={s.kpiCard}>
          <div className={s.kpiLabel}>Trial Users</div>
          <div className={s.kpiValue} style={{ color: '#D29922' }}>
            {fmtNum(summary?.trial_users)}
          </div>
          <div className={s.kpiSub} style={{ color: '#8B949E' }}>
            Active trials
          </div>
        </div>
      </div>

      {/* ── Conversion Funnel ──────────────────────────────── */}
      <SectionHeader icon="V" title="Conversion Funnel" />
      <div className={s.funnelCard}>
        {funnel?.stages?.map((stage, i) => {
          const barPct = (stage.count / maxFunnel) * 100;
          const color = FUNNEL_COLORS[i] || FUNNEL_COLORS[FUNNEL_COLORS.length - 1];
          return (
            <div key={stage.name}>
              <div className={s.funnelRow}>
                <span className={s.funnelStage}>{stage.name}</span>
                <div className={s.funnelBarTrack}>
                  <div
                    className={s.funnelBar}
                    style={{
                      width: `${Math.max(barPct, 3)}%`,
                      background: `linear-gradient(90deg, ${color}88, ${color}44)`,
                    }}
                  />
                </div>
                <span className={s.funnelCount}>{fmtNum(stage.count)}</span>
                <span className={s.funnelPct}>
                  {i === 0 ? '100%' : fmtPct(stage.pct_of_prev)}
                </span>
              </div>
              {i < (funnel.stages.length - 1) && (
                <div className={s.funnelArrow}>
                  {'\u2193'} {fmtPct(funnel.stages[i + 1]?.pct_of_prev)} convert
                </div>
              )}
            </div>
          );
        })}
        {funnel?.biggest_drop?.from && (
          <div className={s.dropoffNote}>
            Biggest drop-off: {funnel.biggest_drop.from} to {funnel.biggest_drop.to} ({fmtPct(funnel.biggest_drop.drop_pct)} lost)
          </div>
        )}
      </div>

      {/* ── Revenue by Tier + Churn Trend ──────────────────── */}
      <SectionHeader icon="#" title="Revenue Breakdown" />
      <div className={s.twoCol}>
        {/* Tier bar chart */}
        <div className={s.tierCard}>
          <h3 className={s.cardTitle}>Revenue by Tier</h3>
          {tiers?.tiers?.map((t) => {
            const barPct = (t.mrr_cents / maxTierMrr) * 100;
            return (
              <div key={t.tier} className={s.tierRow}>
                <span className={s.tierLabel}>{t.tier}</span>
                <div className={s.tierBarTrack}>
                  <div
                    className={s.tierBar}
                    style={{
                      width: `${Math.max(barPct, 1)}%`,
                      background: t.color,
                    }}
                  />
                </div>
                <span className={s.tierAmount}>{fmtUsd(t.mrr_cents)}</span>
                <span className={s.tierUsers}>{t.users} users</span>
              </div>
            );
          })}
        </div>

        {/* Churn trend */}
        <div className={s.churnCard}>
          <h3 className={s.cardTitle}>Monthly Churn Rate</h3>
          <div className={s.churnValue} style={{ color: '#EF4444' }}>
            {fmtPct(summary?.churn_rate_pct)}
          </div>
          <h4 className={s.cardTitle} style={{ marginTop: 16 }}>3-Month Trend</h4>
          <div className={s.churnTrend}>
            {summary?.churn_trend?.map((val, i) => (
              <div key={i} style={{ flex: 1 }}>
                <div className={s.churnDot}>
                  <span style={{ color: '#EF4444', fontWeight: 700 }}>{fmtPct(val)}</span>
                  <span style={{ color: '#8B949E', fontSize: 10 }}>
                    {i === 0 ? '3mo ago' : i === 1 ? '2mo ago' : 'Current'}
                  </span>
                </div>
                <div
                  className={s.churnBar}
                  style={{
                    width: `${(val / maxChurn) * 100}%`,
                    marginTop: 6,
                    opacity: i === 2 ? 1 : 0.5,
                  }}
                />
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── Strategy Rentals + Top Converting Pages ────────── */}
      <SectionHeader icon="~" title="Revenue Streams" />
      <div className={s.twoCol}>
        {/* Strategy Rentals */}
        <div className={s.rentalCard}>
          <h3 className={s.cardTitle}>Strategy Rental Revenue</h3>
          <div className={s.kpiGrid} style={{ marginBottom: 16 }}>
            <div className={s.kpiCard} style={{ padding: '12px 14px' }}>
              <div className={s.kpiLabel}>Total Rentals</div>
              <div className={s.kpiValue} style={{ fontSize: 20 }}>
                {fmtNum(rentals?.total_rentals)}
              </div>
            </div>
            <div className={s.kpiCard} style={{ padding: '12px 14px' }}>
              <div className={s.kpiLabel}>Monthly Revenue</div>
              <div className={s.kpiValue} style={{ fontSize: 20, color: '#22C55E' }}>
                {fmtUsd(rentals?.monthly_rental_revenue_cents)}
              </div>
            </div>
          </div>
          <h4 className={s.cardTitle}>Top 5 Rented Strategies</h4>
          {rentals?.top_strategies?.map((st) => (
            <div key={st.name} className={s.rentalRow}>
              <span className={s.rentalName}>{st.name}</span>
              <div className={s.rentalMeta}>
                <span className={s.rentalCount}>{st.rentals} rentals</span>
                <span className={s.rentalRev}>{fmtUsd(st.revenue_cents)}</span>
              </div>
            </div>
          ))}
        </div>

        {/* Top Converting Pages */}
        <div className={s.pagesCard}>
          <h3 className={s.cardTitle}>Top Converting Pages</h3>
          {pages?.pages?.map((pg) => (
            <div key={pg.path} className={s.pageRow}>
              <span className={s.pagePath}>{pg.path}</span>
              <span className={s.pageUpgrades}>{pg.upgrades} upgrades</span>
              <span className={s.pageConv}>{fmtPct(pg.conversion_pct)}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ── Compute Credits ────────────────────────────────── */}
      <SectionHeader icon="C" title="Compute Credits" />
      <div className={s.computeCard}>
        <div className={s.computeGrid}>
          <div className={s.computeStat}>
            <div className={s.computeStatLabel}>Credits Sold</div>
            <div className={s.computeStatValue} style={{ color: '#60A5FA' }}>
              {fmtNum(compute?.credits_sold)}
            </div>
          </div>
          <div className={s.computeStat}>
            <div className={s.computeStatLabel}>Credits Consumed</div>
            <div className={s.computeStatValue} style={{ color: '#D29922' }}>
              {fmtNum(compute?.credits_consumed)}
            </div>
          </div>
          <div className={s.computeStat}>
            <div className={s.computeStatLabel}>Revenue</div>
            <div className={s.computeStatValue} style={{ color: '#22C55E' }}>
              {fmtUsd(compute?.revenue_cents)}
            </div>
          </div>
          <div className={s.computeStat}>
            <div className={s.computeStatLabel}>Cost</div>
            <div className={s.computeStatValue} style={{ color: '#EF4444' }}>
              {fmtUsd(compute?.cost_cents)}
            </div>
          </div>
          <div className={s.computeStat}>
            <div className={s.computeStatLabel}>Pending</div>
            <div className={s.computeStatValue} style={{ color: '#8B949E' }}>
              {fmtNum(compute?.credits_pending)}
            </div>
          </div>
          <div className={s.computeStat}>
            <div className={s.computeStatLabel}>Margin</div>
            <div className={s.computeStatValue} style={{ color: '#22C55E' }}>
              {fmtPct(compute?.margin_pct)}
            </div>
          </div>
        </div>
      </div>

      {/* ── Cohort Retention Table ─────────────────────────── */}
      <SectionHeader icon="[" title="Cohort Retention" />
      <div className={s.cohortCard}>
        <table className={s.cohortTable}>
          <thead>
            <tr>
              <th>Cohort</th>
              <th>Users</th>
              <th>1 Month</th>
              <th>2 Months</th>
              <th>3 Months</th>
              <th>6 Months</th>
              <th>12 Months</th>
            </tr>
          </thead>
          <tbody>
            {cohorts?.cohorts?.map((c) => (
              <tr key={c.month}>
                <td className={s.cohortMonth}>{c.month}</td>
                <td className={s.cohortUsers}>{fmtNum(c.users)}</td>
                {['1m', '2m', '3m', '6m', '12m'].map((period) => (
                  <td key={period}>
                    {c.retention[period] != null ? (
                      <span className={`${s.cohortCell} ${cohortClass(c.retention[period])}`}>
                        {fmtPct(c.retention[period])}
                      </span>
                    ) : (
                      <span className={s.cohortEmpty}>--</span>
                    )}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
